from tools.implementations.shared import load_image, save_image
import cv2
import numpy as np
from PIL import Image

def run(image_path: str) -> ToolResult:
    try:
        img = load_image(image_path)
        gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
        _, threshed = cv2.threshold(gray, 80, 255, cv2.THRESH_BINARY)

        boxes = cv2.findContours(threshed, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)[-2]
        boxes = [cv2.boundingRect(b) for b in boxes]

        processed_img = img.copy()
        for x, y, w, h in boxes:
