from core.types import ToolResult
from tools.implementations.shared import load_image, save_image
import cv2
import numpy as np
from PIL import Image
import pytesseract


def preprocess_image(img):
    gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
    _, thresh = cv2.threshold(gray, 0, 255, cv2.THRESH_BINARY_INV + cv2.THRESH_OTSU)
    return thresh


def extract_text(img):
    config = "--psm 6"
    text = pytesseract.image_to_string(img, config=config)
    return text


def run(image_path: str) -> ToolResult:
    try:
        img = load_image(image_path)
        processed_img = preprocess_image(img)

        text = extract_text(processed_img)

        output_path = "artifacts/enhanced_ocr_output.png"
        save_image(processed_img, output_path)

        return ToolResult(
            status="ok",
            answer="Extracted text for debugging",  
            artifacts=[output_path],
        )
    except Exception as e:
        return ToolResult(status="error", answer="", error=str(e))


