from core.types import ToolResult
from tools.implementations.shared import load_image, save_image
import cv2
import numpy as np
from PIL import Image

COLOR_TO_EXTRACT = (0, 0, 255)  # Red in BGR


def extract_color_segment(image):
    # Convert image to BGR if it's not
    if isinstance(image, Image.Image):
        image = cv2.cvtColor(np.array(image), cv2.COLOR_RGB2BGR)

    # Create mask for the color
    mask = cv2.inRange(image, COLOR_TO_EXTRACT, COLOR_TO_EXTRACT)

    # Do contour detection and find the bounding rectangle
    contours, _ = cv2.findContours(mask, cv2.RETR_TREE, cv2.CHAIN_APPROX_SIMPLE)
    if not contours:
        return None
    x, y, w, h = cv2.boundingRect(contours[0])

    # Extract the region from original image
    segment = image[y:y+h, x:x+w]
    return segment


def run(image_path: str) -> ToolResult:
    try:
        img = load_image(image_path)
        segment = extract_color_segment(img)

        if segment is None:
            raise ValueError('No segment found.')

        output_path = "artifacts/extracted_segment.png"
        save_image(segment, output_path)

        return ToolResult(
            status="ok",
            answer="",
            artifacts=[output_path],
        )
    except Exception as e:
        return ToolResult(status="error", answer="", error=str(e))


def main():
    import sys
    if len(sys.argv) < 2:
        print(f"Usage: python {sys.argv[0]} <image_path>")
        sys.exit(1)

    print(run(sys.argv[1]))

if __name__ == "__main__":
    main()
